mapper.select:
/* com.erns.coching.rnd.mapper.LabMasterDAO.getList */
SELECT ZZ.* FROM ( SELECT
, A1.MEMB_SEQ AS MEMB_SEQ , A1.MEMB_ID AS MEMB_ID , A1.MEMB_NAME AS MEMB_NAME , (SELECT COUNT(*) FROM T_AI_LAB_RES WHERE LAB_MST_SEQ = AA.LAB_MST_SEQ) AS AI_LAB_RES_CNT FROM T_LAB_MST AA LEFT OUTER JOIN T_MEMB_INF A1 ON AA.CHNR = A1.MEMB_SEQ
ORDER BY AA.CHNG_DTTM DESC
) ZZ
OFFSET #{offset} LIMIT #{rowSize}

/* com.erns.coching.rnd.mapper.LabMasterDAO.load */

SELECT

FROM T_LAB_MST AA

	AND AA.LAB_MST_SEQ 	= #{labMstSeq	, jdbcType=INTEGER}

mapper.insert:
		/* com.erns.coching.rnd.mapper.LabMasterDAO.insert */


			SELECT nextval('seq_t_lab_mst')


		INSERT INTO T_LAB_MST (
			  LAB_MST_SEQ
			, TITLE
			, PROD_CATE_GROUP
			, PROD_CATE_CODE
			, CONTENT

			, RGTR
			, RGT_DTTM
			, CHNR
			, CHNG_DTTM

    ) VALUES (

				#{labMstSeq			, jdbcType=INTEGER}
			, #{title 			  , jdbcType=VARCHAR}
			, #{prodCateGroup	, jdbcType=VARCHAR}
			, #{prodCateCode	, jdbcType=VARCHAR}
			, #{content			  , jdbcType=VARCHAR}

			, #{rgtr	, jdbcType=INTEGER}
			, now()
			, #{chnr	, jdbcType=INTEGER}
			, now()
		)

mapper.update:
/* com.erns.coching.rnd.mapper.LabMasterDAO.update */

UPDATE T_LAB_MST SET
		TITLE     	      = #{title 			  , jdbcType=VARCHAR}
	, PROD_CATE_GROUP   = #{prodCateGroup	, jdbcType=VARCHAR}
	, PROD_CATE_CODE    = #{prodCateCode	, jdbcType=VARCHAR}
	, CONTENT        	  = #{content			  , jdbcType=VARCHAR}

	, CHNR 		 		  = #{chnr				, jdbcType=INTEGER}
	, CHNG_DTTM  		= now()

	AND LAB_MST_SEQ 	= #{labMstSeq			, jdbcType=INTEGER}

mapper.delete:
/* com.erns.coching.rnd.mapper.LabMasterDAO.delete */

DELETE FROM T_LAB_MST

	AND LAB_MST_SEQ = #{labMstSeq, jdbcType=INTEGER}
